const params = $('Extract Parameters').first().json;
const claudeResponse = $input.item.json;

let profile = {};
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  profile = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  return [{ json: { error: 'Failed to parse resume', user_id: params.user_id } }];
}

return [{ json: { user_id: params.user_id, ...profile } }];
